import React, { useState } from "react";
import { AnimatePresence, motion } from "framer-motion";

import AppRoutes from "./routes/AppRoutes";
import Preloader from "./components/Preloader";

const App = () => {

  const [loading, setLoading] = useState(true);

  return (
    <>

      {/* PRELOADER */}
      <AnimatePresence mode="wait">

        {loading && (
          <motion.div
            key="preloader"
            exit={{
              opacity: 0,
              scale: 1.05,
              filter: "blur(10px)",
              transition: {
                duration: 1.2,
                ease: [0.19, 1, 0.22, 1],
              },
            }}
          >
            <Preloader onDone={() => setLoading(false)} />
          </motion.div>
        )}

      </AnimatePresence>

      {/* APP ROUTES */}
      <AnimatePresence>

        {!loading && (
          <motion.div
            key="app"

            initial={{
              opacity: 0,
              y: 40,
              filter: "blur(10px)",
            }}

            animate={{
              opacity: 1,
              y: 0,
              filter: "blur(0px)",
            }}

            transition={{
              duration: 1.4,
              ease: [0.19, 1, 0.22, 1],
            }}
          >
            <AppRoutes />
          </motion.div>
        )}

      </AnimatePresence>

    </>
  );
};

export default App;
